import React from 'react';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
//Browsing page
const Browse = () => {
  return (
    <>
      <Navbar />
      <main>
        <h1>Find a Handyman</h1>
        <p>Browse through trusted professionals near you.</p>
      </main>
      
    </>
  );
};

export default Browse;
